#include <bits/stdc++.h>
using namespace std;
int main(){
    int n,q1=0,q2=0;
    string s,q;
    cin>>s>>q;
    cin>>s>>q;
    for(int i=0;i<q.size();i++){
        if(q[i]=='1')q1++;
        else q2++;
    }
    if(q1%2){
        for(int i=0;i<s.size()/2;i++){
            swap(s[i],s[s.size()-i-1]);
        }
    }
    if(q2%2){
        for(int i=0;i<s.size();i++){
            if(s[i]=='0')s[i]='1';
            else s[i]='0';
        }
    }
    cout<<s;
    return 0;
}
